values.content:
=Write the personalized opener for this prospect.

## Prospect
Name: {{ $json.first_name }} {{ $json.last_name }}
Title: {{ $json.title }}
Company: {{ $json.company_name }}

## Prospect Brief (factual — do NOT contradict)
{{ JSON.stringify($json.prospect_brief) }}

## Pain hypothesis (from qualification)
{{ $json.pain_hypothesis }}

Return JSON in this EXACT schema:
{
  "first_line": "<≤25 words, no greeting, lands fast>",
  "alt_first_line": "<different angle, ≤25 words>",
  "p_s_line": "<≤20 words postscript that adds a second hook or a tiny piece of social proof>",
  "personalization_quality_score": <0-10 integer>,
  "angle_used": "trigger_event" | "role_pain" | "observation_pain" | "social_proof" | "contrarian_take"
}

parameters.jsCode:
const lead = $('When Executed by Parent').item.json;
let p = $input.first().json;
if (p && p.message && p.message.content) {
  try { p = typeof p.message.content === 'string' ? JSON.parse(p.message.content) : p.message.content; }
  catch(e) { p = { first_line:'', alt_first_line:'', p_s_line:'', personalization_quality_score: 0, angle_used:'fallback' }; }
}
return [{ json: { ...lead, personalization: p } }];

